		/*	
		 * Check if there is any matching users: 
		 * 1. Perform EXACT MATCH Search
		 * 2. Perform PARTIAL MATCH Search
		 *
		*/
        import java.text.SimpleDateFormat;  
        import sailpoint.object.Custom;
        import sailpoint.object.Filter;
        import sailpoint.tools.Util;
        import sailpoint.object.Link;
        import sailpoint.object.QueryOptions;
		
		List matchingUsers = new ArrayList();
		
		// Search only Non-HR Contractors
        Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
        List contractorTypes = new ArrayList();
        if(custom!=null && custom.get("ContractorType") !=null ){
			contractorTypes = custom.get("ContractorType"); // non-hr contractor
			
        }
		
        List filterList = new ArrayList();
        List finalFilterList = new ArrayList();        

        Filter empTypeFilter = Filter.in("type", contractorTypes);
        Filter lastnameFilter = Filter.eq("lastname", identityModel.get("lastname"));
		Filter transposedLastNameFilter = Filter.eq("firstname", identityModel.get("lastname"));
        Filter firstnameFilter = Filter.eq("firstname", identityModel.get("firstname"));
		Filter transponsedFirstNameFilter = Filter.eq("lastname", identityModel.get("firstname"));
		Filter ministryFilter = Filter.eq("ministry", identityModel.get("ministry"));
        
		Filter ssnFinalFilter = Filter.eq("ssn", identityModel.get("ssn"));		
		
		if(decryptAES(identityModel.get("ssn")) != null){
			ssnFinalFilter = Filter.or(ssnFinalFilter ,Filter.eq("ssn", decryptAES(identityModel.get("ssn"))));
        } else{
			ssnFinalFilter = Filter.or(ssnFinalFilter ,Filter.eq("ssn", encryptAES(identityModel.get("ssn"))));
        }

        Filter dobFinalFilter = Filter.eq("dob", identityModel.get("dob"));

        if(decryptAES(identityModel.get("dob")) != null){
			dobFinalFilter = Filter.or(dobFinalFilter ,Filter.eq("dob", decryptAES(identityModel.get("dob"))));
        }else{
			dobFinalFilter = Filter.or(dobFinalFilter ,Filter.eq("dob", encryptAES(identityModel.get("dob"))));
        }          

        QueryOptions qo = new QueryOptions();
        qo.add(empTypeFilter, lastnameFilter, firstnameFilter, ssnFinalFilter, dobFinalFilter, ministryFilter);

        List properties = new ArrayList();
        properties.add("name");
        Iterator iter = context.search(Identity.class, qo, properties);

        while(iter.hasNext()) {
			Object[] currentUser = iter.next();
			if(currentUser != null && currentUser.length > 0 && currentUser[0] != null) {
				matchingUsers.add(currentUser[0]);  
			}        
        }

		if(!Util.isEmpty(matchingUsers)){
			// if there any matching users from EXACT Match
			if(matchingUsers.size()==1){
				// if there is only one EXACT MATCH user
				identityModel.put("reenableContractorName",matchingUsers.get(0)) ;
				
				matchingUsers = new ArrayList() ; 
				
				if(null != iter){
					Util.flushIterator(iter);
				}
			}
		} else {
			// if there is no EXACT Match user, then do partial match users search
			filterList.add("firstname,ssn,dob");
			filterList.add("transposedFirstName,ssn,dob");
			filterList.add("lastname,ssn,dob");
			filterList.add("transposedLastName,ssn,dob");
			

			for(Object filter : filterList){    
				StringTokenizer st = new StringTokenizer(filter,",");
				
				// Filter by Non-hr contractor type
				Filter matchFilter = empTypeFilter;
				
				// Filter by ministry
				matchFilter = matchFilter.and(ministryFilter) ;
				
				while (st.hasMoreTokens()) { 
					String filterName = st.nextToken();

					if(Util.nullSafeCaseInsensitiveEq("lastname",filterName)){
						matchFilter = matchFilter.and(matchFilter,lastnameFilter);
					} else if(Util.nullSafeCaseInsensitiveEq("firstname",filterName)){ 
						matchFilter = matchFilter.and(matchFilter,firstnameFilter);      
					} else if(Util.nullSafeCaseInsensitiveEq("ssn",filterName)){
						matchFilter = matchFilter.and(matchFilter,ssnFinalFilter);
					} else if(Util.nullSafeCaseInsensitiveEq("dob",filterName)){
						matchFilter = matchFilter.and(matchFilter,dobFinalFilter);
					} else if(Util.nullSafeCaseInsensitiveEq("transposedFirstName",filterName)){
						matchFilter = matchFilter.and(matchFilter,transponsedFirstNameFilter);
					} else if(Util.nullSafeCaseInsensitiveEq("transposedLastName",filterName)){
						matchFilter = matchFilter.and(matchFilter,transposedLastNameFilter);
					}
				}
				finalFilterList.add(matchFilter);
			}
			
			Filter finalFilter = Filter.or(finalFilterList);
			
			QueryOptions qo = new QueryOptions();
			qo.addFilter(finalFilter);

			Identity launcherID = context.getObjectByName(Identity.class,launcher);

			if ( null != launcherID && Util.isNotNullOrEmpty(launcherID.getStringAttribute("isContractorManager")) && launcherID.getStringAttribute("isContractorManager").equalsIgnoreCase("true"))  {
				Filter managerFilter = Filter.eq("contractorManager", launcherID.getName());
				qo.add(finalFilter, managerFilter);
			}

			Iterator iter = context.search(Identity.class, qo, properties);

			while(iter.hasNext()) {
				Object[] currentUser = iter.next();
				if(currentUser != null && currentUser.length > 0 && currentUser[0] != null) {
				matchingUsers.add(currentUser[0]);  
				}        
			}

			if(null != iter){
				Util.flushIterator(iter);
			}
		}
        return matchingUsers;

