        import sailpoint.api.SailPointContext;
        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
        import sailpoint.object.ProvisioningPlan.Operation;

        ProvisioningPlan plan = new ProvisioningPlan();
        Identity identityObject = null; 
        String identityAttribute = null;
      	String formAttribute = null;
          
        wfcontext.setVariable("enableAccounts","true");
        
        if(null !=identityName){ 
        	identityObject = context.getObjectByName(Identity.class, identityName);
        
        	if(null != identityObject){ 
        		List attributeList = new ArrayList(identityModel.keySet());        		
        		AccountRequest iiqAcctReq = new AccountRequest();
            iiqAcctReq.setApplication("IIQ");
            iiqAcctReq.setNativeIdentity(identityName);
            iiqAcctReq.setOperation(AccountRequest.Operation.Modify);
						if(null != attributeList && !attributeList.isEmpty()){
              for(String eachAttribute : attributeList) { 
                if(eachAttribute != null && (eachAttribute.equals("ssn") || eachAttribute.equals("dob"))) {
                //handling encrypted attributes separately 

                if (identityObject.getAttribute(eachAttribute) != null  && decryptAES(identityObject.getAttribute(eachAttribute)) != null) {
                  identityAttribute = decryptAES(identityObject.getAttribute(eachAttribute));
                }
                else{
                	identityAttribute = identityObject.getAttribute(eachAttribute);
                }
        
                if (identityModel != null && identityModel.get(eachAttribute) != null && decryptAES(identityModel.get("eachAttribute")) != null) {
                  formAttribute = decryptAES(identityModel.get(eachAttribute));
                }
        				else{
        					formAttribute = identityModel.get(eachAttribute);
        				}
                if (!Util.nullSafeEq(identityAttribute, formAttribute, true)) {
                  iiqAcctReq.add(new AttributeRequest(eachAttribute, ProvisioningPlan.Operation.Set, identityModel.get(eachAttribute)));                
                }
              }
              else 	if ( !Util.nullSafeEq(identityObject.getAttribute(eachAttribute), identityModel.get(eachAttribute), true) ) {                 
                   iiqAcctReq.add(new AttributeRequest(eachAttribute, ProvisioningPlan.Operation.Set, identityModel.get(eachAttribute)));                
                }        
              }	
        		}		
            plan.add(iiqAcctReq);
            plan.setIdentity(identityObject);
            //comment decache //context.decache(identityObject);
        	}
        }       
        return plan;

      import sailpoint.object.IdentityRequest;
      import sailpoint.api.ObjectUtil;
        
      IdentityRequest iRequest = ObjectUtil.transactionLock(context, IdentityRequest.class, identityRequestId);
			if(iRequest!=null){
          iRequest.setExternalTicketId(iiqIdentityRequestId);
          context.saveObject(iRequest);
          context.commitTransaction();
          //comment decache //context.decache(iRequest);
       }
